// Package imports:
import 'package:collection/collection.dart';
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/subscription_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_team_check.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

/// 現在のチームおよび現在のユーザー（Apple ID）に対する
/// 有料プランの所有・利用可能状態を表します。
enum SubscriptionStatus {
  /// 現在のチームに対する有料プランを自分が所有している（Apple IAP）。
  subscribedByMe,

  /// プランの更新中。
  updating,

  /// 自分は有料プランを所有しているが、別のチームでの契約である。
  subscribedByMeInOtherTeam,

  /// チームは Web/Stripe で有料プランを契約中（Apple のトランザクションは存在しない）。
  subscribedOnWeb,

  /// 現在のチームでは別のメンバーが有料プランを所有している（Apple IAP）。
  subscribedByTeammate,

  /// 現在のチームにもユーザーにも有効な有料プランがない。
  notSubscribed,
  ;

  /// 端末上で購入・アップグレードが可能かどうか
  bool get canSubscribe => switch (this) {
        SubscriptionStatus.notSubscribed ||
        SubscriptionStatus.subscribedByMe =>
          true,
        _ => false,
      };

  /// プランの更新中かどうか
  bool get isUpdating => this == updating;
}

SubscriptionStatus? useSubscriptionStatus() {
  final ref = useWidgetRef();
  final currentEntitlementState = ref.watch(subscriptionControllerProvider);
  final teamList = ref.watch(teamListControllerProvider);
  final teamId = ref.watch(profileStorageProvider).getTeamId();

  // 初回マウント時に最新化のため invalidate する
  useEffectOnce(() {
    // ビルド直後に安全に実行するため microtask で包む
    Future.microtask(() {
      ref
          .read(subscriptionControllerProvider.notifier)
          .updateCurrentEntitlement();
      ref.read(teamListControllerProvider.notifier).refreshKeepingPrevious();
    });
    return null;
  });

  final currentEntitlement = currentEntitlementState.when(
    loading: () => null,
    error: (_, __) => null,
    data: (data) => data,
  );

  final (hasActivePaidPlan, team) = teamList.fold(
      loading: () => (null, null),
      error: (_) => (null, null),
      data: (result) {
        final team = result.firstWhereOrNull((team) => team.id == teamId);
        // 現在有効なプランが存在する && そのプランが有料プランである
        final hasActivePaidPlan = team?.teamPlanStatus.isAvailable == true &&
            team?.teamPlan?.plan?.isPaid == true;

        return (hasActivePaidPlan, team);
      });

  // CurrentEntitlement(CE) の有無をベースに課金導線が表示可能かどうかを判断する
  // 1. CE あり : CE.appAccountToken == teamId (自身の契約)
  // 2. CE あり : CE.appAccountToken == teamId && CE.webOrderLineItemId != teamPlan.appleSubscription.webOrderLineItemId (契約の更新中)
  // 3. CE あり : CE.appAccountToken != teamId (自分は他のチームで契約しつつ、現在表示中のチームは別の人が有料契約している)
  //
  // 4. CE なし : teamPlan.stripeSubscription あり (Stripe で Web から契約)
  // 5. CE なし : teamPlan.stripeSubscription なし (チームに所属する別ユーザーが Apple で契約)
  // 6. CE なし : teamPlan に有効な有料契約なし
  //
  // 1, 6 で課金導線を表示する

  // ガード：ローディング/エラー中は判定不可
  if (hasActivePaidPlan == null) return null;

  // CE あり
  if (currentEntitlement != null) {
    if (currentEntitlement.appAccountToken == teamId) {
      if (currentEntitlement.webOrderLineItemID ==
          team?.teamPlan?.appleSubscription?.webOrderLineItemId) {
        // 1
        return SubscriptionStatus.subscribedByMe;
      } else {
        // 2
        return SubscriptionStatus.updating;
      }
    } else {
      // 3
      return SubscriptionStatus.subscribedByMeInOtherTeam;
    }
  }

  // CE なし
  if (hasActivePaidPlan) {
    return team?.teamPlan?.isStripeSubscription == true
        // 4
        ? SubscriptionStatus.subscribedOnWeb
        // 5
        : SubscriptionStatus.subscribedByTeammate;
  }

  // 6
  return SubscriptionStatus.notSubscribed;
}

(bool, SubscriptionStatus?, String?) useSubscription() {
  final context = useContext();
  final status = useSubscriptionStatus();
  final isSingleUserTeam = useSingleTeamCheck();

  final subscriptionNotAvailableMessage = switch (status) {
    SubscriptionStatus.subscribedByMeInOtherTeam => context.l10n
        .settings_page__subscription_restriction__subscribed_by_me_in_other_team,
    SubscriptionStatus.subscribedByTeammate => context
        .l10n.settings_page__subscription_restriction__subscribed_by_teammate,
    SubscriptionStatus.subscribedOnWeb =>
      context.l10n.settings_page__subscription_restriction__subscribed_on_web,
    _ => null,
  };

  return (
    isSingleUserTeam && (status?.canSubscribe ?? false),
    status,
    subscriptionNotAvailableMessage,
  );
}

/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/resource_data_detail_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/data/upload_queue.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/components/custom_alert_snack_bar.dart';
import 'package:baseball_detector_flutter/views/hooks/use_rerender.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/resource_details/components/resource_reanalyze_dialog.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/resource_details/components/resource_upload_dialog.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class ResourceDetailsSnackbar extends HookConsumerWidget {
  const ResourceDetailsSnackbar({
    required this.resource,
    super.key,
  });

  final ResourceData resource;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final rerender = useRerender();
    // 状態に応じたスナックバーの設定を取得
    final snackBarConfig = _getSnackBarConfig(
      context,
      ref,
      rerender,
    );

    // 表示するものがない場合は空のウィジェットを返す
    if (snackBarConfig == null) return const SizedBox.shrink();

    return CustomAlertSnackBar(
      showCloseIcon: false,
      backgroundColor: snackBarConfig.backgroundColor,
      foregroundColor: Colors.white,
      icon: snackBarConfig.icon,
      child: snackBarConfig.child,
    );
  }

  /// リソースの状態に応じたスナックバーの設定を取得する
  _SnackBarConfig? _getSnackBarConfig(
    BuildContext context,
    WidgetRef ref,
    VoidCallback rerender,
  ) {
    return switch (resource.statusType) {
      ResourceStatusType.analysisSucceeded => null,
      ResourceStatusType.onAnalysisServerQueue ||
      ResourceStatusType.inAnalysis =>
        _SnackBarConfig(
          backgroundColor: ColorManager.main,
          icon: Icons.info_outline,
          child: Text(context.l10n.resource_details_page__processing_video),
        ),
      ResourceStatusType.analysisFailed => _SnackBarConfig(
          backgroundColor: ColorManager.error,
          icon: Icons.error_outline,
          child: Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(context.l10n.resource_details_page__analysis_failed),
              _buildTappableText(
                context.l10n.resource_details_page__try_again,
                () => _showResourceDialog(
                  context,
                  ref,
                  AppRouter.reanalyzeResourceDialog,
                  ResourceReanalyzeDialog(
                    resource: resource,
                    onSucceeded: () {
                      rerender();
                      // Also invalidate the resource data detail controller to force refresh
                      ref.invalidate(resourceDataDetailControllerProvider(
                        teamId: resource.teamId!,
                        sessionId: resource.sessionId!,
                        resourceId: resource.id!,
                      ));
                    },
                  ),
                  ResourceStatusType.analysisFailed,
                ),
              ),
            ],
          ),
        ),
      ResourceStatusType.onLocalStorage => ref
              .read(uploadQueueProvider)
              .contains(resource)
          ? _SnackBarConfig(
              backgroundColor: ColorManager.main,
              icon: Icons.info_outline,
              child: Text(context.l10n.resource_details_page__on_upload_queue),
            )
          : _SnackBarConfig(
              backgroundColor: ColorManager.darkGrey,
              icon: Icons.error_outline,
              child: Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Text(context.l10n.resource_details_page__on_local_storage),
                  _buildTappableText(
                    context.l10n.resource_details_page__try_again,
                    () => _showResourceDialog(
                      context,
                      ref,
                      AppRouter.uploadResourceDialog,
                      ResourceUploadDialog(
                        resource: resource,
                        onSucceeded: rerender,
                      ),
                      ResourceStatusType.onLocalStorage,
                    ),
                  ),
                ],
              ),
            ),
      _ => null,
    };
  }

  /// リソース関連のダイアログを表示する
  void _showResourceDialog(
    BuildContext context,
    WidgetRef ref,
    String routeName,
    Widget dialog,
    ResourceStatusType expectedStatusType,
  ) {
    assert(resource.statusType == expectedStatusType);
    assert(!ref.read(uploadQueueProvider).contains(resource));

    showDialog(
      context: context,
      barrierDismissible: true,
      routeSettings: RouteSettings(
        name: routeName,
        arguments: {'resourceId': resource.id},
      ),
      builder: (_) => dialog,
    );
  }

  Widget _buildTappableText(String text, void Function() onTap) {
    return Consumer(
      builder: (context, ref, _) {
        final teamListState = ref.watch(teamListControllerProvider);
        final teamId = ref.watch(profileStorageProvider).getTeamId();

        return teamListState.fold(
          data: (teams) {
            final team = teams.where((team) => team.id == teamId!).firstOrNull;
            if (team?.teamPlanStatus.isAvailable != true) {
              return const SizedBox.shrink();
            }

            return GestureDetector(
              onTap: onTap,
              child: Text(
                text,
                style: const TextStyle(decoration: TextDecoration.underline),
              ),
            );
          },
          error: (error) => const SizedBox.shrink(),
          loading: () => const SizedBox.shrink(),
        );
      },
    );
  }
}

